// ---------------------------------------------------
// When asynchronous TcpSend is complete...
// ---------------------------------------------------
void OnTcpSend( dword socket, long result, char buffer[], dword size)
{
  if (socket != ~0)
  {
    // sending data complete.
    If (result != 0)
    {
      writeLineEx(1, 3, “OnTcpSend error: %d”, result);
    }
  }
}
